func processItems(items <-chan int, results chan<- int, done chan<- bool) {
    for item := range items {
        results <- item * 2
    }
    done <- true
}

import "sync"

func runConcurrently(tasks []func()) {
    var wg sync.WaitGroup
    for _, task := range tasks {
        wg.Add(1)
        go func(t func()) {
            defer wg.Done()
            t()
        }(task)
    }
    wg.Wait()
}
